import{_ as i,o as l,c as o,a6 as a}from"./chunks/framework.B-2qg3-Z.js";const _=JSON.parse('{"title":"设计边界","description":"","frontmatter":{},"headers":[],"relativePath":"guide/boundary.md","filePath":"guide/boundary.md"}'),d={name:"guide/boundary.md"};function r(t,e,c,n,s,p){return l(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="设计边界" tabindex="-1">设计边界 <a class="header-anchor" href="#设计边界" aria-label="Permalink to &quot;设计边界&quot;">​</a></h1><p>核心库不绑定具体业务规则。</p><p>宿主系统负责判断：</p><ul><li>谁发现谁</li><li>谁锁定谁</li><li>谁攻击谁</li><li>谁毁伤或失联</li><li>哪些模型、关系、效果需要在某一帧显示</li></ul><p>组件库负责：</p><ul><li>地图初始化</li><li>模型显示与更新</li><li>航向、目标线和关系线显示</li><li>标绘、测量、截图、导入导出</li><li>态势特效渲染</li><li>回放和高频刷新优化</li></ul><h2 id="推荐发布入口" tabindex="-1">推荐发布入口 <a class="header-anchor" href="#推荐发布入口" aria-label="Permalink to &quot;推荐发布入口&quot;">​</a></h2><p>推荐作为正式发布入口使用：</p><ul><li><code>ScenarioEditor</code></li><li><code>createScenarioEditor()</code></li><li><code>openlayers2dsceneeditor/style.css</code></li></ul><p>兼容层仍保留但不建议新项目依赖：</p><ul><li><code>mapApp</code></li><li><code>modelList</code></li><li><code>selectedModel</code></li><li><code>mapBridge</code> 的散装函数导出</li></ul><h2 id="接入建议" tabindex="-1">接入建议 <a class="header-anchor" href="#接入建议" aria-label="Permalink to &quot;接入建议&quot;">​</a></h2><p>业务系统应该围绕 <code>ScenarioEditor</code> 组件或 <code>createScenarioEditor()</code> 返回的 editor 实例组织调用。</p><p>不要直接修改内部 <code>sceneStore</code> 状态。需要改变场景时，通过公开 API 更新模型、关系线、特效和显示配置。</p>',14)])])}const h=i(d,[["render",r]]);export{_ as __pageData,h as default};
